messages.content:
Analyze the following JSON PRD and design resource access interfaces.

JSON PRD:
```json
{
  "metadata": {
    "project_name": "Student Grade System",
    "project_id": "com.example.studentgrades",
    "version": "1.0.0"
  },
  "functional_requirements": [
    {
      "fr_id": "FR-001",
      "title": "Record Grade",
      "description": "Teacher records a grade for a student in a course. Validates student existence, course existence, score range (0-100), and no duplicate grade for the same student-course pair.",
      "priority": "high",
      "related_nfr_ids": [],
      "depends_on": []
    },
    {
      "fr_id": "FR-002",
      "title": "Update Grade",
      "description": "Teacher updates an existing grade record. Validates grade record existence and updates score and recorded_at timestamp.",
      "priority": "high",
      "related_nfr_ids": [],
      "depends_on": [
        "FR-001"
      ]
    },
    {
      "fr_id": "FR-003",
      "title": "Delete Grade",
      "description": "Teacher deletes a grade record. Validates grade record existence and removes it.",
      "priority": "high",
      "related_nfr_ids": [],
      "depends_on": [
        "FR-001"
      ]
    },
    {
      "fr_id": "FR-004",
      "title": "Get Student Grades",
      "description": "Retrieve all grades for a student, compute average score, total credits, and GPA. Display grades with course name, score, and letter grade.",
      "priority": "high",
      "related_nfr_ids": [],
      "depends_on": [
        "FR-001"
      ]
    },
    {
      "fr_id": "FR-005",
      "title": "Get Course Grades",
      "description": "Retrieve all grades for a course, compute average, max, min scores, and distribution of letter grades.",
      "priority": "high",
      "related_nfr_ids": [],
      "depends_on": [
        "FR-001"
      ]
    },
    {
      "fr_id": "FR-006",
      "title": "List Grades by Class",
      "description": "List grades for students in a specific class, optionally filtered by course. Compute class average and rank students by score.",
      "priority": "medium",
      "related_nfr_ids": [],
      "depends_on": [
        "FR-001"
      ]
    },
    {
      "fr_id": "FR-007",
      "title": "Get Grade Report",
      "description": "Generate a textual report for a student including all subject grades, average, GPA, and credit summary.",
      "priority": "medium",
      "related_nfr_ids": [],
      "depends_on": [
        "FR-004"
      ]
    },
    {
      "fr_id": "FR-008",
      "title": "Get Course Statistics",
      "description": "Compute statistics for a course: average, standard deviation, pass rate, and grade distribution percentages.",
      "priority": "medium",
      "related_nfr_ids": [],
      "depends_on": [
        "FR-005"
      ]
    },
    {
      "fr_id": "FR-009",
      "title": "Add Student",
      "description": "Add a new student to the system. Validates that student_id is unique.",
      "priority": "low",
      "related_nfr_ids": [],
      "depends_on": []
    },
    {
      "fr_id": "FR-010",
      "title": "Add Course",
      "description": "Add a new course to the system. Validates that course_id is unique.",
      "priority": "low",
      "related_nfr_ids": [],
      "depends_on": []
    }
  ],
  "non_functional_requirements": [
    {
      "nfr_id": "NFR-001",
      "category": "usability",
      "description": "The system should provide clear error messages for invalid operations (e.g., duplicate grade, non-existent student)."
    },
    {
      "nfr_id": "NFR-002",
      "category": "reliability",
      "description": "Data integrity must be maintained: no duplicate grades for same student-course, valid score range."
    }
  ],
  "acceptance_criteria": [
    {
      "ac_id": "AC-001",
      "description": "Record grade: valid input creates grade record with correct grade_id and letter grade.",
      "verification_method": "automated_test",
      "related_fr_ids": [
        "FR-001"
      ]
    },
    {
      "ac_id": "AC-002",
      "description": "Record grade: duplicate student-course returns error with existing grade_id.",
      "verification_method": "automated_test",
      "related_fr_ids": [
        "FR-001"
      ]
    },
    {
      "ac_id": "AC-003",
      "description": "Update grade: valid update changes score and returns new letter grade.",
      "verification_method": "automated_test",
      "related_fr_ids": [
        "FR-002"
      ]
    },
    {
      "ac_id": "AC-004",
      "description": "Delete grade: valid deletion removes record and returns success.",
      "verification_method": "automated_test",
      "related_fr_ids": [
        "FR-003"
      ]
    },
    {
      "ac_id": "AC-005",
      "description": "Get student grades: returns correct average, total credits, GPA, and grade details.",
      "verification_method": "automated_test",
      "related_fr_ids": [
        "FR-004"
      ]
    },
    {
      "ac_id": "AC-006",
      "description": "Get course grades: returns correct average, max, min, and distribution.",
      "verification_method": "automated_test",
      "related_fr_ids": [
        "FR-005"
      ]
    },
    {
      "ac_id": "AC-007",
      "description": "List grades by class: returns students with scores and ranks, class average correct.",
      "verification_method": "automated_test",
      "related_fr_ids": [
        "FR-006"
      ]
    },
    {
      "ac_id": "AC-008",
      "description": "Get grade report: generates text report with all required fields.",
      "verification_method": "manual_review",
      "related_fr_ids": [
        "FR-007"
      ]
    },
    {
      "ac_id": "AC-009",
      "description": "Get course statistics: computes average, std_dev, pass_rate, grade distribution correctly.",
      "verification_method": "automated_test",
      "related_fr_ids": [
        "FR-008"
      ]
    },
    {
      "ac_id": "AC-010",
      "description": "Add student: new student added successfully, duplicate student_id rejected.",
      "verification_method": "automated_test",
      "related_fr_ids": [
        "FR-009"
      ]
    },
    {
      "ac_id": "AC-011",
      "description": "Add course: new course added successfully, duplicate course_id rejected.",
      "verification_method": "automated_test",
      "related_fr_ids": [
        "FR-010"
      ]
    }
  ],
  "technical_constraints": {
    "storage": {
      "type": "memory",
      "details": "Three independent in-memory data sources: students, courses, grades."
    },
    "concurrency": {
      "model": "single-user",
      "auth_required": false
    },
    "ui": {
      "type": "api",
      "details": "Function-based interface via manage_grade(command, grade_data)."
    },
    "language": "Python"
  },
  "glossary": {
    "GPA": "Grade Point Average, calculated as weighted average of grade points (A=4.0, B=3.0, C=2.0, D=1.0, F=0) multiplied by course credits.",
    "Letter Grade": "Grade classification: A (90-100), B (80-89), C (70-79), D (60-69), F (<60).",
    "Pass Rate": "Percentage of students with score >= 60.",
    "Standard Deviation": "Measure of score dispersion from the mean."
  },
  "global_state_sources": [
    {
      "source_id": "students",
      "type": "dict",
      "description": "Stores student information keyed by student_id.",
      "initial_state": {
        "1": {
          "student_id": 1,
          "name": "张明",
          "class": "A班",
          "enrollment_year": 2022
        },
        "2": {
          "student_id": 2,
          "name": "李华",
          "class": "A班",
          "enrollment_year": 2022
        },
        "3": {
          "student_id": 3,
          "name": "王芳",
          "class": "A班",
          "enrollment_year": 2022
        },
        "4": {
          "student_id": 4,
          "name": "刘强",
          "class": "A班",
          "enrollment_year": 2022
        },
        "5": {
          "student_id": 5,
          "name": "陈静",
          "class": "A班",
          "enrollment_year": 2022
        },
        "6": {
          "student_id": 6,
          "name": "赵伟",
          "class": "B班",
          "enrollment_year": 2022
        },
        "7": {
          "student_id": 7,
          "name": "周婷",
          "class": "B班",
          "enrollment_year": 2022
        },
        "8": {
          "student_id": 8,
          "name": "吴刚",
          "class": "B班",
          "enrollment_year": 2022
        },
        "9": {
          "student_id": 9,
          "name": "孙丽",
          "class": "B班",
          "enrollment_year": 2022
        },
        "10": {
          "student_id": 10,
          "name": "钱杰",
          "class": "B班",
          "enrollment_year": 2022
        }
      },
      "item_schema": {
        "student_id": "int",
        "name": "string",
        "class": "string",
        "enrollment_year": "int"
      }
    },
    {
      "source_id": "courses",
      "type": "dict",
      "description": "Stores course information keyed by course_id.",
      "initial_state": {
        "1": {
          "course_id": 1,
          "name": "数学",
          "credit": 4,
          "teacher": "王老师"
        },
        "2": {
          "course_id": 2,
          "name": "英语",
          "credit": 3,
          "teacher": "李老师"
        },
        "3": {
          "course_id": 3,
          "name": "物理",
          "credit": 3,
          "teacher": "张老师"
        },
        "4": {
          "course_id": 4,
          "name": "化学",
          "credit": 2,
          "teacher": "陈老师"
        }
      },
      "item_schema": {
        "course_id": "int",
        "name": "string",
        "credit": "int",
        "teacher": "string"
      }
    },
    {
      "source_id": "grades",
      "type": "dict",
      "description": "Stores grade records keyed by grade_id. Also maintains a set of (student_id, course_id) pairs to enforce uniqueness.",
      "initial_state": {},
      "item_schema": {
        "grade_id": "int",
        "student_id": "int",
        "course_id": "int",
        "score": "int",
        "recorded_at": "datetime"
      }
    }
  ],
  "input_spec": {
    "format": "json",
    "description": "Input is provided via the function manage_grade(command, grade_data) where command is a string and grade_data is a JSON object.",
    "schema": {
      "command": "string (one of: record_grade, update_grade, delete_grade, get_student_grades, get_course_grades, list_class_grades, get_grade_report, get_course_stats, add_student, add_course)",
      "grade_data": {
        "student_id": "int (optional)",
        "course_id": "int (optional)",
        "score": "int (0-100, optional)",
        "grade_id": "int (optional)",
        "class": "string (optional)",
        "name": "string (optional, for add_student/add_course)",
        "credit": "int (optional, for add_course)",
        "teacher": "string (optional, for add_course)",
        "enrollment_year": "int (optional, for add_student)"
      }
    },
    "examples": [
      {
        "command": "record_grade",
        "grade_data": {
          "student_id": 1,
          "course_id": 1,
          "score": 92
        }
      },
      {
        "command": "update_grade",
        "grade_data": {
          "grade_id": 1,
          "score": 88
        }
      },
      {
        "command": "get_student_grades",
        "grade_data": {
          "student_id": 1
        }
      }
    ]
  },
  "output_spec": {
    "format": "json",
    "description": "Output is a JSON object with success flag, message, and data payload.",
    "schema": {
      "success": "boolean",
      "message": "string",
      "data": "object (varies by command)"
    },
    "examples": [
      {
        "success": true,
        "message": "成绩记录成功",
        "data": {
          "grade_id": 1,
          "letter_grade": "A"
        }
      },
      {
        "success": false,
        "message": "该学生此课程已有成绩记录",
        "data": {
          "existing_grade_id": 1
        }
      },
      {
        "success": true,
        "data": {
          "grades": [
            {
              "course": "数学",
              "score": 88,
              "letter": "B",
              "credit": 4
            }
          ],
          "average": 88,
          "total_credits": 4,
          "gpa": 3.0
        }
      }
    ]
  }
}
```

Remember:
- Choose storage model from: dict, list, in_memory_table
- Choose operations from: get, list, create, update, delete, exists
- Do NOT create business action interfaces like pay_order or ship_order
- Create only low-level CRUD interfaces
- Every resource needs at least a get interface
